external_knowledge:
- 'Treasures' refer to the datasets;
- 'Unearthed within the last year's exploration' refers to datasets uploaded within the last year;
- 'Realm of ChIP-Seq' refers to datasets of type 'ChIP-Seq';
- 'Weigh more than a mere drop' refers to file sizes greater than 1 MB;
- 'Sorted by their heft from the most substantial to the least' refers to sorting the file sizes in descending order.

sql:
SELECT overlap_id, LOG2(p_value) AS p_value_log2
FROM overlap
WHERE overlap_number > 10;

SELECT overlap_number, p_value, adjusted_p_value, overlap_type
FROM overlap
WHERE dataset_id = 1;

SELECT model_id, dataset_id
FROM model_datasets
WHERE training_date >= '2023-01-01';

SELECT name
FROM datasets
WHERE dataset_id IN (SELECT overlap_dataset_id FROM overlap);

SELECT gene_id, dataset_id
FROM gene_datasets
WHERE expression_level > 100;

SELECT COUNT(DISTINCT dataset_id) 
FROM files 
WHERE public_access = 1;
